const UA = 'Mozilla/5.0 (compatible; NefalixSikayetvarSync/1.0)';
const DELAY_MS = Number($env.SIKAYETVAR_REQUEST_DELAY_SEC || 2) * 1000;
const BRAND_RE = /title\\":\\"([^\\]+)\\",\\"href\\":\\"([^\\]+)\\"[^}]*complaintId\\":(\d+)/g;
const JINA_LINK_RE = /\[([^\]]+)\]\((https:\/\/www\.sikayetvar\.com\/[^)\s]+)/g;
const EXCERPT_RE = /lg:inline">([^<]{40,4000})<\/span>/;
const CHILDREN_RE = /children\\":\\"([^\\]{80,4000})\\"/g;

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!sbKey) throw new Error('SUPABASE_SERVICE_ROLE_KEY eksik');
const sbH = { apikey: sbKey, Authorization: `Bearer ${sbKey}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' };
const webhookBase = ($env.WEBHOOK_URL || $env.N8N_WEBHOOK_URL || 'http://127.0.0.1:5678/').replace(/\/$/, '');
const clinicFilter = $json.body?.clinic_id || $json.clinic_id || null;
const dryRun = Boolean($json.body?.dryRun || $json.dryRun);
const forceJina = ['1','true','yes','jina'].includes(String($env.SIKAYETVAR_USE_JINA || '').toLowerCase());
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function sb(method, path, body) {
  return await this.helpers.httpRequest({ method, url: `${sbBase}/rest/v1/${path}`, headers: sbH, body, json: true });
}

async function fetchPage(url) {
  if (forceJina) {
    const body = await this.helpers.httpRequest({ method: 'GET', url: `https://r.jina.ai/${url}`, headers: { 'User-Agent': UA }, json: false });
    return { body, mode: 'jina' };
  }
  try {
    const body = await this.helpers.httpRequest({ method: 'GET', url, headers: { 'User-Agent': UA }, json: false });
    return { body, mode: 'direct' };
  } catch (e) {
    const msg = String(e.message || e);
    const code = e.statusCode || e.httpCode || Number((msg.match(/status code (\d+)/i) || [])[1]) || 0;
    if ([403, 429, 503].includes(code) || /403|429|blocked/i.test(msg)) {
      const body = await this.helpers.httpRequest({ method: 'GET', url: `https://r.jina.ai/${url}`, headers: { 'User-Agent': UA }, json: false });
      return { body, mode: 'jina' };
    }
    throw e;
  }
}


function pathFromSikayetvarUrl(url) {
  const m = String(url).match(/sikayetvar\.com(\/[^?\s#]+)/i);
  return (m ? m[1] : '').replace(/^\/|\/$/g, '');
}

function decodeHtml(s) {
  return String(s || '').replace(/&#x27;/g, "'").replace(/&quot;/g, '"').replace(/&amp;/g, '&');
}

function parseBrandJina(text, profileUrl) {
  const brandPath = pathFromSikayetvarUrl(profileUrl).split('/').filter(Boolean)[0] || '';
  const out = [];
  const seen = new Set();
  let m;
  const re = new RegExp(JINA_LINK_RE.source, 'g');
  while ((m = re.exec(text)) !== null) {
    const title = m[1].trim();
    const url = m[2].split('"')[0].trim();
    const path = pathFromSikayetvarUrl(url);
    if (!path.startsWith(`${brandPath}/`) || path === brandPath) continue;
    const extId = path.split('/').pop();
    if (seen.has(extId)) continue;
    seen.add(extId);
    let excerpt = '';
    const pos = text.indexOf(url);
    if (pos >= 0) {
      const lines = text.slice(pos, pos + 1200).split('\n').map((l) => l.trim()).filter(Boolean);
      for (const ln of lines.slice(2, 6)) {
        if (ln.startsWith('[') || ln.startsWith('!')) continue;
        if (ln.length > 60) { excerpt = ln; break; }
      }
    }
    out.push({ external_id: extId, title, href: `/${path}`, url, excerpt });
  }
  return out;
}

function parseBrand(html, profileUrl, mode) {
  if (mode === 'jina' || html.includes('Markdown Content:')) return parseBrandJina(html, profileUrl);
  const out = [];
  const seen = new Set();
  let m;
  const re = new RegExp(BRAND_RE.source, 'g');
  while ((m = re.exec(html)) !== null) {
    const [, title, href, cid] = m;
    if (seen.has(cid)) continue;
    seen.add(cid);
    const path = href.startsWith('/') ? href : `/${href}`;
    out.push({ external_id: cid, title: decodeHtml(title), href: path, url: `https://www.sikayetvar.com${path}` });
  }
  return out.length ? out : parseBrandJina(html, profileUrl);
}

function parseExcerpt(html, title, mode) {
  if (mode === 'jina' || html.includes('Markdown Content:')) {
    for (const ln of html.split('\n')) {
      const text = ln.trim();
      if (text.length < 80) continue;
      const low = text.toLowerCase();
      if (/(markdown content|url source|title:)/i.test(low)) continue;
      if (title.toLowerCase().slice(0, 30) && low.includes(title.toLowerCase().slice(0, 30)) && text.length < title.length + 30) continue;
      if (/\d{2}\.\d{2}\.\d{4}/.test(text) || /(dolgu|ağrı|diş|klinik|mağdur|işlem)/i.test(low)) return text;
    }
    return title;
  }
  const ex = html.match(EXCERPT_RE);
  if (ex && ex[1] && !ex[1].startsWith('...')) return decodeHtml(ex[1]).trim();
  const lowTitle = title.toLowerCase();
  let chunk;
  const re = new RegExp(CHILDREN_RE.source, 'g');
  while ((chunk = re.exec(html)) !== null) {
    const text = decodeHtml(chunk[1]).trim();
    const low = text.toLowerCase();
    if (text.length < 80) continue;
    if (lowTitle.slice(0, 40) && low.includes(lowTitle.slice(0, 40)) && text.length < title.length + 20) continue;
    if (/(şikayetvar|tüm markalar|404|aydınlatma)/i.test(low)) continue;
    if (/(dolgu|ağrı|diş|klinik|doktor|hasta|mağdur)/i.test(low)) return text;
  }
  return title;
}

async function alreadySynced(clinicId, externalId, url) {
  for (const q of [
    `reputation_mentions?clinic_id=eq.${clinicId}&source=eq.sikayetvar&external_id=eq.${encodeURIComponent(externalId)}&select=id&limit=1`,
    `reputation_mentions?clinic_id=eq.${clinicId}&source=eq.sikayetvar&url=eq.${encodeURIComponent(url)}&select=id&limit=1`,
  ]) {
    const rows = await sb.call(this, 'GET', q);
    if (Array.isArray(rows) && rows.length) return true;
  }
  const events = await sb.call(this, 'GET', `automation_events?clinic_id=eq.${clinicId}&event_type=eq.sikayetvar_forwarded&payload->>complaintId=eq.${encodeURIComponent(externalId)}&select=id&limit=1`);
  return Array.isArray(events) && events.length > 0;
}

let clinicQuery = 'clinics?select=id,name,sikayetvar_url&sikayetvar_url=not.is.null&order=name.asc';
if (clinicFilter) clinicQuery = `clinics?select=id,name,sikayetvar_url&id=eq.${clinicFilter}`;
const clinics = await sb.call(this, 'GET', clinicQuery);
if (!clinics?.length) throw new Error('sikayetvar_url olan klinik yok');

const results = [];
for (const clinic of clinics) {
  const profileUrl = (clinic.sikayetvar_url || '').trim();
  if (!profileUrl) {
    results.push({ clinic: clinic.name, ok: false, error: 'sikayetvar_url yok' });
    continue;
  }
  try {
    const { body: brandHtml, mode: fetchMode } = await fetchPage.call(this, profileUrl);
    const complaints = parseBrand(brandHtml, profileUrl, fetchMode);
    let forwarded = 0;
    let skipped = 0;
    const details = [];
    for (let i = 0; i < complaints.length; i++) {
      const c = complaints[i];
      if (await alreadySynced.call(this, clinic.id, c.external_id, c.url)) {
        skipped++;
        continue;
      }
      if (i > 0) await sleep(DELAY_MS);
      let excerpt = c.excerpt || '';
      if (!excerpt) {
        const { body: detailHtml, mode: detailMode } = await fetchPage.call(this, c.url);
        excerpt = parseExcerpt(detailHtml, c.title, detailMode);
      }
      const content = excerpt && excerpt !== c.title ? `${c.title}\n\n${excerpt}` : c.title;
      if (!dryRun) {
        await this.helpers.httpRequest({
          method: 'POST',
          url: `${webhookBase}/webhook/nefalix/sentinel/mention`,
          headers: { 'Content-Type': 'application/json' },
          body: {
            source: 'sikayetvar',
            platform: 'sikayetvar',
            clinic_id: clinic.id,
            brandName: clinic.name,
            text: content,
            content,
            url: c.url,
            external_id: c.external_id,
          },
          json: true,
        });
        await sb.call(this, 'POST', 'automation_events', {
          clinic_id: clinic.id,
          workflow_name: 'nefalix-14-sikayetvar-sync',
          event_type: 'sikayetvar_forwarded',
          payload: { complaintId: c.external_id, url: c.url, title: c.title },
        });
        await sleep(DELAY_MS);
      }
      forwarded++;
      details.push({ id: c.external_id, title: c.title, dryRun, fetchMode });
    }
    if (!dryRun) {
      await sb.call(this, 'PATCH', `clinics?id=eq.${clinic.id}`, { sikayetvar_synced_at: new Date().toISOString() });
    }
    results.push({ clinic: clinic.name, ok: true, listed: complaints.length, forwarded, skipped, fetchMode, details });
  } catch (e) {
    results.push({ clinic: clinic.name, ok: false, error: e.message });
  }
}

return [{ json: { ok: true, at: new Date().toISOString(), dryRun, results } }];
